import { useState } from 'react';
import type { PatternAsset } from '@/types';

interface PatternPanelProps {
  patterns: PatternAsset[];
  onSelectPattern: (pattern: PatternAsset | null) => void;
}

const categories = [
  { id: 'all', name: '全部' },
  { id: 'cloud', name: '云纹' },
  { id: 'flame', name: '火焰' },
  { id: 'dragon', name: '龙凤' },
  { id: 'flower', name: '花卉' },
  { id: 'geometric', name: '几何' },
];

export default function PatternPanel({ patterns, onSelectPattern }: PatternPanelProps) {
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [selectedPattern, setSelectedPattern] = useState<PatternAsset | null>(null);

  const filteredPatterns =
    selectedCategory === 'all'
      ? patterns
      : patterns.filter((p) => p.category === selectedCategory);

  const handleSelectPattern = (pattern: PatternAsset) => {
    setSelectedPattern(pattern);
    onSelectPattern(pattern);
  };

  return (
    <div className="space-y-4">
      {/* 分类筛选 */}
      <div className="flex flex-wrap gap-2">
        {categories.map((cat) => (
          <button
            key={cat.id}
            onClick={() => setSelectedCategory(cat.id)}
            className={`px-3 py-1.5 text-xs rounded-full transition-colors ${
              selectedCategory === cat.id
                ? 'bg-yellow-500 text-zinc-900 font-semibold'
                : 'bg-zinc-700/50 text-zinc-300 hover:bg-zinc-700'
            }`}
          >
            {cat.name}
          </button>
        ))}
      </div>

      {/* 纹饰网格 */}
      <div className="grid grid-cols-2 gap-3">
        {filteredPatterns.map((pattern) => (
          <button
            key={pattern.id}
            onClick={() => handleSelectPattern(pattern)}
            className={`group bg-zinc-700/30 rounded-xl p-4 hover:bg-zinc-700/50 transition-all text-left ${
              selectedPattern?.id === pattern.id ? 'ring-2 ring-yellow-500' : ''
            }`}
          >
            <div className="text-3xl mb-2">{pattern.thumbnail}</div>
            <div className="text-sm font-medium text-white group-hover:text-yellow-500 transition-colors">
              {pattern.name}
            </div>
            <div className="text-xs text-zinc-400 mt-1 line-clamp-2">{pattern.description}</div>
          </button>
        ))}
      </div>

      {/* 选中纹饰详情 */}
      {selectedPattern && (
        <div className="bg-zinc-700/30 rounded-lg p-4 border border-zinc-700/50">
          <div className="flex items-start gap-3">
            <div className="text-4xl">{selectedPattern.thumbnail}</div>
            <div className="flex-1">
              <h4 className="text-sm font-semibold text-white">{selectedPattern.name}</h4>
              <p className="text-xs text-zinc-400 mt-1">{selectedPattern.description}</p>
              {selectedPattern.unlockCondition && (
                <p className="text-xs text-yellow-500 mt-2">
                  🔓 解锁条件: {selectedPattern.unlockCondition}
                </p>
              )}
            </div>
          </div>
          <button
            onClick={() => {
              setSelectedPattern(null);
              onSelectPattern(null);
            }}
            className="w-full mt-3 py-2 text-sm text-zinc-400 hover:text-white transition-colors border border-zinc-600 rounded-lg hover:border-zinc-500"
          >
            取消选择
          </button>
        </div>
      )}

      {/* 使用提示 */}
      <div className="bg-zinc-700/20 rounded-lg p-4 border border-zinc-700/50">
        <h4 className="text-sm font-semibold text-zinc-300 mb-2">使用说明</h4>
        <div className="space-y-1 text-xs text-zinc-400">
          <p>1. 选择想要添加的纹饰</p>
          <p>2. 点击脸谱上想要装饰的区域</p>
          <p>3. 完成知识问答可解锁更多纹饰</p>
        </div>
      </div>
    </div>
  );
}
