import { useRef, useState } from 'react';
import { useFrame, ThreeEvent } from '@react-three/fiber';
import * as THREE from 'three';
import { useMaskStore } from '@/store/useMaskStore';
import type { MaskWork, RegionData } from '@/types';

interface MaskModelProps {
  work: MaskWork;
}

const regions = {
  forehead: { position: [0, 1.2, 1.51], scale: [1.4, 0.6, 0.1] },
  leftCheek: { position: [-0.8, 0.2, 1.51], scale: [0.7, 0.8, 0.1] },
  rightCheek: { position: [0.8, 0.2, 1.51], scale: [0.7, 0.8, 0.1] },
  leftEye: { position: [-0.5, 0.6, 1.52], scale: [0.5, 0.3, 0.1] },
  rightEye: { position: [0.5, 0.6, 1.52], scale: [0.5, 0.3, 0.1] },
  nose: { position: [0, 0.3, 1.52], scale: [0.3, 0.6, 0.1] },
  mouth: { position: [0, -0.4, 1.52], scale: [0.6, 0.3, 0.1] },
  chin: { position: [0, -1.2, 1.51], scale: [1, 0.5, 0.1] },
};

export default function MaskModel({ work }: MaskModelProps) {
  const groupRef = useRef<THREE.Group>(null);
  const [hoveredRegion, setHoveredRegion] = useState<string | null>(null);
  const { selectedColor, updateRegion, selectedRegion } = useMaskStore();

  useFrame((state) => {
    if (groupRef.current) {
      groupRef.current.rotation.y = Math.sin(state.clock.elapsedTime * 0.3) * 0.1;
    }
  });

  const handleRegionClick = (regionName: string) => {
    const newRegionData: RegionData = {
      color: selectedColor,
      pattern: null,
    };
    updateRegion(regionName, newRegionData);
  };

  const handleRegionHover = (regionName: string | null) => {
    setHoveredRegion(regionName);
    document.body.style.cursor = regionName ? 'pointer' : 'default';
  };

  return (
    <group ref={groupRef} position={[0, 0, 0]}>
      {/* 底层脸谱 - 使用简单的球体变形 */}
      <mesh position={[0, 0, 0]}>
        <sphereGeometry args={[1.5, 32, 32]} />
        <meshStandardMaterial color="#F5DEB3" roughness={0.6} metalness={0.1} />
      </mesh>

      {/* 各个区域 */}
      {Object.entries(regions).map(([name, config]) => {
        const regionData = work.regions[name as keyof typeof work.regions];
        const isHovered = hoveredRegion === name;
        const isSelected = selectedRegion === name;

        return (
          <mesh
            key={name}
            position={config.position as [number, number, number]}
            onClick={(e: ThreeEvent<MouseEvent>) => {
              e.stopPropagation();
              handleRegionClick(name);
            }}
            onPointerOver={(e: ThreeEvent<PointerEvent>) => {
              e.stopPropagation();
              handleRegionHover(name);
            }}
            onPointerOut={() => handleRegionHover(null)}
          >
            <boxGeometry args={config.scale as [number, number, number]} />
            <meshStandardMaterial
              color={regionData?.color || '#FFFFFF'}
              roughness={0.5}
              metalness={0.1}
              transparent
              opacity={isHovered || isSelected ? 0.9 : 1}
              emissive={isHovered || isSelected ? '#FFFFFF' : '#000000'}
              emissiveIntensity={isHovered || isSelected ? 0.2 : 0}
            />
          </mesh>
        );
      })}

      {/* 眼睛 */}
      <mesh position={[-0.5, 0.6, 1.53]}>
        <sphereGeometry args={[0.15, 16, 16]} />
        <meshStandardMaterial color="#000000" roughness={0.3} metalness={0.5} />
      </mesh>
      <mesh position={[0.5, 0.6, 1.53]}>
        <sphereGeometry args={[0.15, 16, 16]} />
        <meshStandardMaterial color="#000000" roughness={0.3} metalness={0.5} />
      </mesh>

      {/* 眉毛 */}
      <mesh position={[-0.5, 0.85, 1.53]} rotation={[0, 0, 0.3]}>
        <boxGeometry args={[0.5, 0.08, 0.05]} />
        <meshStandardMaterial color="#000000" roughness={0.4} />
      </mesh>
      <mesh position={[0.5, 0.85, 1.53]} rotation={[0, 0, -0.3]}>
        <boxGeometry args={[0.5, 0.08, 0.05]} />
        <meshStandardMaterial color="#000000" roughness={0.4} />
      </mesh>
    </group>
  );
}
