import { useState } from 'react';
import type { ColorPalette } from '@/types';

interface ToolPanelProps {
  palettes: ColorPalette[];
  onSelectColor: (color: string) => void;
}

const basicColors = [
  '#C8102E', '#DC2626', '#EF4444', // 红色系
  '#FFD700', '#F59E0B', '#FBBF24', // 金黄色系
  '#1A1A1A', '#374151', '#6B7280', // 黑灰色系
  '#FFFFFF', '#F3F4F6', '#E5E7EB', // 白色系
  '#1E40AF', '#3B82F6', '#60A5FA', // 蓝色系
  '#047857', '#10B981', '#34D399', // 绿色系
  '#7C3AED', '#8B5CF6', '#A78BFA', // 紫色系
];

export default function ToolPanel({ palettes, onSelectColor }: ToolPanelProps) {
  const [selectedColor, setSelectedColor] = useState('#C8102E');
  const [showCustom, setShowCustom] = useState(false);

  const handleColorSelect = (color: string) => {
    setSelectedColor(color);
    onSelectColor(color);
  };

  return (
    <div className="space-y-6">
      {/* 经典配色方案 */}
      <div>
        <h4 className="text-sm font-semibold text-zinc-300 mb-3">经典配色方案</h4>
        <div className="space-y-3">
          {palettes.map((palette) => (
            <div
              key={palette.id}
              className="bg-zinc-700/30 rounded-lg p-3 hover:bg-zinc-700/50 transition-colors cursor-pointer"
            >
              <div className="flex items-center justify-between mb-2">
                <span className="text-sm font-medium text-white">{palette.name}</span>
                <span className="text-xs text-zinc-400">{palette.characterType}</span>
              </div>
              <div className="flex gap-1">
                {palette.colors.map((color, index) => (
                  <button
                    key={index}
                    onClick={() => handleColorSelect(color)}
                    className="w-8 h-8 rounded-lg border-2 border-zinc-600 hover:border-yellow-500 transition-colors"
                    style={{ backgroundColor: color }}
                    title={color}
                  />
                ))}
              </div>
              <p className="text-xs text-zinc-400 mt-2">{palette.description}</p>
            </div>
          ))}
        </div>
      </div>

      {/* 基础色板 */}
      <div>
        <h4 className="text-sm font-semibold text-zinc-300 mb-3">基础色板</h4>
        <div className="grid grid-cols-3 gap-2">
          {basicColors.map((color) => (
            <button
              key={color}
              onClick={() => handleColorSelect(color)}
              className={`w-full aspect-square rounded-lg border-2 transition-all hover:scale-110 ${
                selectedColor === color
                  ? 'border-yellow-500 ring-2 ring-yellow-500/50'
                  : 'border-zinc-600 hover:border-zinc-500'
              }`}
              style={{ backgroundColor: color }}
              title={color}
            />
          ))}
        </div>
      </div>

      {/* 自定义颜色 */}
      <div>
        <button
          onClick={() => setShowCustom(!showCustom)}
          className="w-full text-sm text-yellow-500 hover:text-yellow-400 transition-colors text-left"
        >
          {showCustom ? '收起自定义颜色' : '展开自定义颜色'}
        </button>
        {showCustom && (
          <div className="mt-3">
            <input
              type="color"
              value={selectedColor}
              onChange={(e) => handleColorSelect(e.target.value)}
              className="w-full h-12 rounded-lg cursor-pointer border-2 border-zinc-600 hover:border-yellow-500 transition-colors"
            />
            <p className="text-xs text-zinc-400 mt-2">
              当前颜色: <span className="text-white font-mono">{selectedColor}</span>
            </p>
          </div>
        )}
      </div>

      {/* 颜色说明 */}
      <div className="bg-zinc-700/20 rounded-lg p-4 border border-zinc-700/50">
        <h4 className="text-sm font-semibold text-zinc-300 mb-2">颜色寓意</h4>
        <div className="space-y-1 text-xs text-zinc-400">
          <p>🔴 红色 - 忠义、正直、英勇</p>
          <p>⚪ 白色 - 奸诈、阴险、多疑</p>
          <p>⚫ 黑色 - 刚正、无私、粗鲁</p>
          <p>🔵 蓝色 - 刚强、骁勇、有心计</p>
          <p>🟡 金色 - 神圣、威严、庄重</p>
        </div>
      </div>
    </div>
  );
}
