import { useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowLeft, BookOpen, Palette, Users, History, Trophy, X, CheckCircle } from 'lucide-react';
import { knowledgeArticles, quizzes, colorPalettes } from '@/data';
import type { KnowledgeArticle, Quiz as QuizType } from '@/types';

const categoryIcons = {
  role: Users,
  color: Palette,
  pattern: BookOpen,
  history: History,
};

const categoryNames = {
  role: '行当角色',
  color: '色彩寓意',
  pattern: '纹饰图案',
  history: '历史渊源',
};

export default function Knowledge() {
  const [activeCategory, setActiveCategory] = useState<string>('all');
  const [selectedArticle, setSelectedArticle] = useState<KnowledgeArticle | null>(null);
  const [showQuiz, setShowQuiz] = useState(false);
  const [currentQuizIndex, setCurrentQuizIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [showResult, setShowResult] = useState(false);
  const [score, setScore] = useState(0);
  const [answeredQuizzes, setAnsweredQuizzes] = useState<Set<string>>(new Set());

  const filteredArticles =
    activeCategory === 'all'
      ? knowledgeArticles
      : knowledgeArticles.filter((a) => a.category === activeCategory);

  const handleStartQuiz = () => {
    setShowQuiz(true);
    setCurrentQuizIndex(0);
    setSelectedAnswer(null);
    setShowResult(false);
    setScore(0);
    setAnsweredQuizzes(new Set());
  };

  const handleAnswerSelect = (index: number) => {
    if (showResult) return;
    setSelectedAnswer(index);
  };

  const handleSubmitAnswer = () => {
    if (selectedAnswer === null) return;

    const currentQuiz = quizzes[currentQuizIndex];
    const isCorrect = selectedAnswer === currentQuiz.correctAnswer;

    if (isCorrect) {
      setScore(score + 1);
    }

    setAnsweredQuizzes(new Set([...answeredQuizzes, currentQuiz.id]));
    setShowResult(true);
  };

  const handleNextQuestion = () => {
    if (currentQuizIndex < quizzes.length - 1) {
      setCurrentQuizIndex(currentQuizIndex + 1);
      setSelectedAnswer(null);
      setShowResult(false);
    } else {
      setShowQuiz(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-zinc-900 via-zinc-800 to-zinc-900">
      {/* Header */}
      <header className="bg-zinc-800/80 backdrop-blur-sm border-b border-zinc-700 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link
                to="/"
                className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors"
              >
                <ArrowLeft className="w-5 h-5" />
              </Link>
              <div>
                <h1 className="text-xl font-bold text-white">知识科普</h1>
                <p className="text-sm text-zinc-400">探索京剧脸谱文化</p>
              </div>
            </div>
            <button
              onClick={handleStartQuiz}
              className="flex items-center gap-2 px-4 py-2 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-lg transition-colors"
            >
              <Trophy className="w-4 h-4" />
              知识问答
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* 分类筛选 */}
        <div className="flex flex-wrap gap-3 mb-8">
          <button
            onClick={() => setActiveCategory('all')}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-colors ${
              activeCategory === 'all'
                ? 'bg-yellow-500 text-zinc-900'
                : 'bg-zinc-800 text-zinc-300 hover:bg-zinc-700'
            }`}
          >
            全部
          </button>
          {Object.entries(categoryNames).map(([key, name]) => {
            const Icon = categoryIcons[key as keyof typeof categoryIcons];
            return (
              <button
                key={key}
                onClick={() => setActiveCategory(key)}
                className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-colors ${
                  activeCategory === key
                    ? 'bg-yellow-500 text-zinc-900'
                    : 'bg-zinc-800 text-zinc-300 hover:bg-zinc-700'
                }`}
              >
                <Icon className="w-4 h-4" />
                {name}
              </button>
            );
          })}
        </div>

        {/* 文章列表 */}
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredArticles.map((article) => {
            const Icon = categoryIcons[article.category];
            return (
              <button
                key={article.id}
                onClick={() => setSelectedArticle(article)}
                className="group bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50 hover:border-yellow-500/50 transition-all text-left hover:scale-[1.02]"
              >
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-10 h-10 rounded-lg bg-zinc-700 flex items-center justify-center">
                    <Icon className="w-5 h-5 text-yellow-500" />
                  </div>
                  <span className="text-xs text-zinc-400">
                    {categoryNames[article.category]}
                  </span>
                </div>
                <h3 className="text-lg font-bold text-white mb-2 group-hover:text-yellow-500 transition-colors">
                  {article.title}
                </h3>
                <p className="text-sm text-zinc-400 line-clamp-3">{article.content}</p>
              </button>
            );
          })}
        </div>

        {/* 经典配色展示 */}
        <section className="mt-12">
          <h2 className="text-2xl font-bold text-white mb-6">经典配色方案</h2>
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
            {colorPalettes.map((palette) => (
              <div
                key={palette.id}
                className="bg-zinc-800/50 backdrop-blur-sm rounded-xl p-5 border border-zinc-700/50"
              >
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-semibold text-white">{palette.name}</h3>
                  <span className="text-xs text-zinc-400">{palette.characterType}</span>
                </div>
                <div className="flex gap-2 mb-3">
                  {palette.colors.map((color, index) => (
                    <div
                      key={index}
                      className="w-10 h-10 rounded-lg border-2 border-zinc-600"
                      style={{ backgroundColor: color }}
                    />
                  ))}
                </div>
                <p className="text-sm text-zinc-400">{palette.description}</p>
              </div>
            ))}
          </div>
        </section>
      </main>

      {/* 文章详情弹窗 */}
      {selectedArticle && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-zinc-800 rounded-2xl max-w-2xl w-full max-h-[80vh] overflow-y-auto">
            <div className="sticky top-0 bg-zinc-800 border-b border-zinc-700 p-6 flex items-center justify-between">
              <h2 className="text-xl font-bold text-white">{selectedArticle.title}</h2>
              <button
                onClick={() => setSelectedArticle(null)}
                className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            </div>
            <div className="p-6">
              <p className="text-zinc-300 leading-relaxed">{selectedArticle.content}</p>
              <div className="mt-6 pt-6 border-t border-zinc-700">
                <Link
                  to="/create"
                  className="inline-flex items-center gap-2 text-yellow-500 hover:text-yellow-400 transition-colors"
                >
                  去创作相关脸谱 →
                </Link>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* 知识问答弹窗 */}
      {showQuiz && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-zinc-800 rounded-2xl max-w-lg w-full">
            <div className="p-6 border-b border-zinc-700">
              <div className="flex items-center justify-between">
                <div>
                  <h2 className="text-xl font-bold text-white">知识问答</h2>
                  <p className="text-sm text-zinc-400">
                    第 {currentQuizIndex + 1} / {quizzes.length} 题
                  </p>
                </div>
                <button
                  onClick={() => setShowQuiz(false)}
                  className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>
              <div className="mt-4 h-2 bg-zinc-700 rounded-full overflow-hidden">
                <div
                  className="h-full bg-yellow-500 transition-all duration-300"
                  style={{ width: `${((currentQuizIndex + 1) / quizzes.length) * 100}%` }}
                />
              </div>
            </div>

            <div className="p-6">
              <p className="text-lg text-white mb-6">{quizzes[currentQuizIndex].question}</p>

              <div className="space-y-3">
                {quizzes[currentQuizIndex].options.map((option, index) => {
                  const isSelected = selectedAnswer === index;
                  const isCorrect = index === quizzes[currentQuizIndex].correctAnswer;
                  const showCorrect = showResult && isCorrect;
                  const showWrong = showResult && isSelected && !isCorrect;

                  return (
                    <button
                      key={index}
                      onClick={() => handleAnswerSelect(index)}
                      disabled={showResult}
                      className={`w-full p-4 rounded-xl text-left transition-all ${
                        showCorrect
                          ? 'bg-green-500/20 border-2 border-green-500'
                          : showWrong
                          ? 'bg-red-500/20 border-2 border-red-500'
                          : isSelected
                          ? 'bg-yellow-500/20 border-2 border-yellow-500'
                          : 'bg-zinc-700/50 border-2 border-zinc-600 hover:border-zinc-500'
                      }`}
                    >
                      <div className="flex items-center gap-3">
                        <span
                          className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-semibold ${
                            showCorrect
                              ? 'bg-green-500 text-white'
                              : showWrong
                              ? 'bg-red-500 text-white'
                              : isSelected
                              ? 'bg-yellow-500 text-zinc-900'
                              : 'bg-zinc-600 text-zinc-300'
                          }`}
                        >
                          {showCorrect ? <CheckCircle className="w-5 h-5" /> : String.fromCharCode(65 + index)}
                        </span>
                        <span className="text-zinc-200">{option}</span>
                      </div>
                    </button>
                  );
                })}
              </div>

              {showResult && (
                <div className="mt-6 p-4 bg-zinc-700/30 rounded-xl">
                  <p className="text-sm text-zinc-300">{quizzes[currentQuizIndex].explanation}</p>
                  <p className="text-sm text-yellow-500 mt-2">
                    🎁 {quizzes[currentQuizIndex].reward}
                  </p>
                </div>
              )}

              <div className="mt-6 flex gap-3">
                {!showResult ? (
                  <button
                    onClick={handleSubmitAnswer}
                    disabled={selectedAnswer === null}
                    className="flex-1 py-3 bg-yellow-500 hover:bg-yellow-400 disabled:bg-zinc-600 disabled:cursor-not-allowed text-zinc-900 font-semibold rounded-xl transition-colors"
                  >
                    确认答案
                  </button>
                ) : (
                  <button
                    onClick={handleNextQuestion}
                    className="flex-1 py-3 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-xl transition-colors"
                  >
                    {currentQuizIndex < quizzes.length - 1 ? '下一题' : '完成'}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
