import { useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowLeft, Plus, Trash2, Edit, Share2, ShoppingBag } from 'lucide-react';
import { useMaskStore } from '@/store/useMaskStore';
import { baseModels } from '@/data';
import FacePreview from '@/components/FacePreview';
import type { MaskWork } from '@/types';

export default function Gallery() {
  const { works, loadWork, deleteWork } = useMaskStore();
  const [selectedWorkId, setSelectedWorkId] = useState<string | null>(null);

  const selectedWork = works.find((w) => w.id === selectedWorkId);

  const handleEdit = (id: string) => {
    loadWork(id);
    window.location.href = '/create';
  };

  const handleDelete = (id: string) => {
    if (confirm('确定要删除这个作品吗？')) {
      deleteWork(id);
      if (selectedWorkId === id) {
        setSelectedWorkId(null);
      }
    }
  };

  const formatDate = (timestamp: number) => {
    return new Date(timestamp).toLocaleDateString('zh-CN', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  };

  // 示例社区作品
  const communityWorks = [
    {
      id: 'demo-1',
      name: '关羽脸谱',
      author: '文化爱好者',
      likes: 128,
      baseModel: 'warrior' as const,
      regions: {
        forehead: { color: '#C8102E', pattern: null },
        leftCheek: { color: '#C8102E', pattern: null },
        rightCheek: { color: '#C8102E', pattern: null },
        leftEye: { color: '#000000', pattern: null },
        rightEye: { color: '#000000', pattern: null },
        nose: { color: '#FFD700', pattern: null },
        mouth: { color: '#DC2626', pattern: null },
        chin: { color: '#C8102E', pattern: null },
      },
    },
    {
      id: 'demo-2',
      name: '包公脸谱',
      author: '京剧迷',
      likes: 96,
      baseModel: 'standard' as const,
      regions: {
        forehead: { color: '#1A1A1A', pattern: null },
        leftCheek: { color: '#1A1A1A', pattern: null },
        rightCheek: { color: '#1A1A1A', pattern: null },
        leftEye: { color: '#FFFFFF', pattern: null },
        rightEye: { color: '#FFFFFF', pattern: null },
        nose: { color: '#FFD700', pattern: null },
        mouth: { color: '#DC2626', pattern: null },
        chin: { color: '#1A1A1A', pattern: null },
      },
    },
    {
      id: 'demo-3',
      name: '孙悟空脸谱',
      author: '神话爱好者',
      likes: 156,
      baseModel: 'warrior' as const,
      regions: {
        forehead: { color: '#FFD700', pattern: null },
        leftCheek: { color: '#FF6B00', pattern: null },
        rightCheek: { color: '#FF6B00', pattern: null },
        leftEye: { color: '#000000', pattern: null },
        rightEye: { color: '#000000', pattern: null },
        nose: { color: '#FFFFFF', pattern: null },
        mouth: { color: '#DC2626', pattern: null },
        chin: { color: '#FFD700', pattern: null },
      },
    },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-zinc-900 via-zinc-800 to-zinc-900">
      {/* Header */}
      <header className="bg-zinc-800/80 backdrop-blur-sm border-b border-zinc-700 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <Link
                to="/"
                className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors"
              >
                <ArrowLeft className="w-5 h-5" />
              </Link>
              <div>
                <h1 className="text-xl font-bold text-white">作品展示</h1>
                <p className="text-sm text-zinc-400">我的创作与社区精选</p>
              </div>
            </div>
            <Link
              to="/create"
              className="flex items-center gap-2 px-4 py-2 bg-red-600 hover:bg-red-500 text-white font-semibold rounded-lg transition-colors"
            >
              <Plus className="w-4 h-4" />
              创作新作品
            </Link>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* 我的作品 */}
        <section className="mb-12">
          <h2 className="text-2xl font-bold text-white mb-6">我的作品</h2>
          {works.length === 0 ? (
            <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-12 border border-zinc-700/50 text-center">
              <div className="text-6xl mb-4">🎭</div>
              <h3 className="text-xl font-semibold text-white mb-2">还没有作品</h3>
              <p className="text-zinc-400 mb-6">开始创作你的第一个脸谱作品吧！</p>
              <Link
                to="/create"
                className="inline-flex items-center gap-2 px-6 py-3 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-xl transition-colors"
              >
                <Plus className="w-5 h-5" />
                开始创作
              </Link>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {works.map((work) => {
                const modelInfo = baseModels.find((m) => m.id === work.baseModel);
                return (
                  <div
                    key={work.id}
                    className="group bg-zinc-800/50 backdrop-blur-sm rounded-2xl border border-zinc-700/50 hover:border-yellow-500/50 transition-all overflow-hidden"
                  >
                    {/* 预览区 */}
                    <div className="aspect-square bg-gradient-to-br from-zinc-700 to-zinc-800 flex items-center justify-center relative p-4">
                      <FacePreview work={work} size={160} />
                      <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                        <button
                          onClick={() => handleEdit(work.id)}
                          className="p-2 bg-zinc-700 hover:bg-zinc-600 rounded-lg transition-colors"
                          title="编辑"
                        >
                          <Edit className="w-5 h-5 text-white" />
                        </button>
                        <button
                          onClick={() => setSelectedWorkId(work.id)}
                          className="p-2 bg-zinc-700 hover:bg-zinc-600 rounded-lg transition-colors"
                          title="查看详情"
                        >
                          <Share2 className="w-5 h-5 text-white" />
                        </button>
                        <button
                          onClick={() => handleDelete(work.id)}
                          className="p-2 bg-red-600 hover:bg-red-500 rounded-lg transition-colors"
                          title="删除"
                        >
                          <Trash2 className="w-5 h-5 text-white" />
                        </button>
                      </div>
                    </div>

                    {/* 信息区 */}
                    <div className="p-4">
                      <h3 className="font-semibold text-white mb-1 truncate">{work.name}</h3>
                      <p className="text-xs text-zinc-400 mb-3">{formatDate(work.updatedAt)}</p>
                      <div className="flex gap-1">
                        {Object.values(work.regions)
                          .slice(0, 4)
                          .map((region, index) => (
                            <div
                              key={index}
                              className="w-6 h-6 rounded-full border border-zinc-600"
                              style={{ backgroundColor: region.color }}
                            />
                          ))}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </section>

        {/* 社区精选 */}
        <section>
          <h2 className="text-2xl font-bold text-white mb-6">社区精选</h2>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {communityWorks.map((work) => (
              <div
                key={work.id}
                className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl border border-zinc-700/50 hover:border-yellow-500/50 transition-all overflow-hidden"
              >
                <div className="aspect-square bg-gradient-to-br from-zinc-700 to-zinc-800 flex items-center justify-center p-4">
                  <FacePreview work={work as unknown as MaskWork} size={140} />
                </div>
                <div className="p-4">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="font-semibold text-white">{work.name}</h3>
                    <span className="text-sm text-red-400">❤️ {work.likes}</span>
                  </div>
                  <p className="text-xs text-zinc-400 mb-3">作者: {work.author}</p>
                  <div className="flex gap-1">
                    {Object.values(work.regions).slice(0, 3).map((region, index) => (
                      <div
                        key={index}
                        className="w-6 h-6 rounded-full border border-zinc-600"
                        style={{ backgroundColor: region.color }}
                      />
                    ))}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>
      </main>

      {/* 作品详情弹窗 */}
      {selectedWork && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-zinc-800 rounded-2xl max-w-lg w-full">
            <div className="aspect-square bg-gradient-to-br from-zinc-700 to-zinc-800 flex items-center justify-center rounded-t-2xl p-8">
              <FacePreview work={selectedWork} size={200} />
            </div>
            <div className="p-6">
              <h2 className="text-xl font-bold text-white mb-2">{selectedWork.name}</h2>
              <p className="text-sm text-zinc-400 mb-4">
                创建于 {formatDate(selectedWork.createdAt)}
              </p>

              <div className="mb-6">
                <h4 className="text-sm font-semibold text-zinc-300 mb-2">使用的颜色</h4>
                <div className="flex flex-wrap gap-2">
                  {Object.entries(selectedWork.regions).map(([name, region]) => (
                    <div key={name} className="flex items-center gap-2">
                      <div
                        className="w-8 h-8 rounded-lg border border-zinc-600"
                        style={{ backgroundColor: region.color }}
                      />
                    </div>
                  ))}
                </div>
              </div>

              <div className="flex gap-3">
                <button
                  onClick={() => handleEdit(selectedWork.id)}
                  className="flex-1 flex items-center justify-center gap-2 py-3 bg-zinc-700 hover:bg-zinc-600 text-white rounded-xl transition-colors"
                >
                  <Edit className="w-4 h-4" />
                  继续编辑
                </button>
                <Link
                  to="/order"
                  className="flex-1 flex items-center justify-center gap-2 py-3 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-xl transition-colors"
                >
                  <ShoppingBag className="w-4 h-4" />
                  定制实体
                </Link>
              </div>

              <button
                onClick={() => setSelectedWorkId(null)}
                className="w-full mt-3 py-2 text-zinc-400 hover:text-white transition-colors"
              >
                关闭
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
