import { useState } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';
import { Link } from 'react-router-dom';
import { ArrowLeft, Save, Undo, Redo, Download } from 'lucide-react';
import { useMaskStore } from '@/store/useMaskStore';
import { colorPalettes, patternAssets, baseModels } from '@/data';
import MaskModel from '@/components/MaskModel';
import ToolPanel from '@/components/ToolPanel';
import PatternPanel from '@/components/PatternPanel';
import type { MaskWork } from '@/types';

export default function Create() {
  const {
    currentWork,
    createNewWork,
    setSelectedColor,
    setSelectedPattern,
    setSelectedRegion,
    saveWork,
    undo,
    redo,
    history,
    historyIndex,
  } = useMaskStore();

  const [showModelSelect, setShowModelSelect] = useState(!currentWork);
  const [activeTab, setActiveTab] = useState<'colors' | 'patterns'>('colors');

  const handleSelectModel = (modelId: MaskWork['baseModel']) => {
    createNewWork(modelId);
    setShowModelSelect(false);
  };

  const handleSave = () => {
    saveWork();
    alert('作品已保存！');
  };

  const canUndo = historyIndex >= 0;
  const canRedo = historyIndex < history.length - 1;

  if (showModelSelect) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-zinc-900 via-zinc-800 to-zinc-900 p-8">
        <div className="max-w-4xl mx-auto">
          <Link
            to="/"
            className="inline-flex items-center gap-2 text-zinc-400 hover:text-white mb-8 transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
            返回首页
          </Link>

          <h1 className="text-3xl font-bold text-white mb-2">选择脸谱基础模型</h1>
          <p className="text-zinc-400 mb-8">选择一个基础模型开始创作你的专属脸谱</p>

          <div className="grid grid-cols-2 gap-6">
            {baseModels.map((model) => (
              <button
                key={model.id}
                onClick={() => handleSelectModel(model.id as MaskWork['baseModel'])}
                className="group bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-8 border border-zinc-700/50 hover:border-yellow-500/50 transition-all duration-300 hover:scale-[1.02] text-left"
              >
                <div className="text-5xl mb-4">{model.thumbnail}</div>
                <h3 className="text-xl font-bold text-white mb-2 group-hover:text-yellow-500 transition-colors">
                  {model.name}
                </h3>
                <p className="text-zinc-400 text-sm">{model.description}</p>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-screen bg-zinc-900 flex flex-col">
      <header className="bg-zinc-800/80 backdrop-blur-sm border-b border-zinc-700 px-4 py-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Link
              to="/"
              className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </Link>
            <div>
              <h1 className="text-lg font-bold text-white">{currentWork?.name}</h1>
              <p className="text-xs text-zinc-400">
                {baseModels.find((m) => m.id === currentWork?.baseModel)?.name}
              </p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={undo}
              disabled={!canUndo}
              className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
              title="撤销"
            >
              <Undo className="w-5 h-5" />
            </button>
            <button
              onClick={redo}
              disabled={!canRedo}
              className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors disabled:opacity-30 disabled:cursor-not-allowed"
              title="重做"
            >
              <Redo className="w-5 h-5" />
            </button>
            <div className="w-px h-6 bg-zinc-700 mx-2" />
            <button
              onClick={handleSave}
              className="flex items-center gap-2 px-4 py-2 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-lg transition-colors"
            >
              <Save className="w-4 h-4" />
              保存
            </button>
            <Link
              to="/order"
              className="flex items-center gap-2 px-4 py-2 bg-red-600 hover:bg-red-500 text-white font-semibold rounded-lg transition-colors"
            >
              <Download className="w-4 h-4" />
              定制实体
            </Link>
          </div>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <aside className="w-80 bg-zinc-800/50 border-r border-zinc-700 flex flex-col">
          <div className="flex border-b border-zinc-700">
            <button
              onClick={() => setActiveTab('colors')}
              className={`flex-1 py-3 text-sm font-medium transition-colors ${
                activeTab === 'colors'
                  ? 'text-yellow-500 border-b-2 border-yellow-500'
                  : 'text-zinc-400 hover:text-white'
              }`}
            >
              配色方案
            </button>
            <button
              onClick={() => setActiveTab('patterns')}
              className={`flex-1 py-3 text-sm font-medium transition-colors ${
                activeTab === 'patterns'
                  ? 'text-yellow-500 border-b-2 border-yellow-500'
                  : 'text-zinc-400 hover:text-white'
              }`}
            >
              纹饰素材
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-4">
            {activeTab === 'colors' ? (
              <ToolPanel
                palettes={colorPalettes}
                onSelectColor={setSelectedColor}
              />
            ) : (
              <PatternPanel
                patterns={patternAssets}
                onSelectPattern={setSelectedPattern}
              />
            )}
          </div>
        </aside>

        <main className="flex-1 relative">
          <div className="absolute inset-0 bg-gradient-to-b from-zinc-900 to-zinc-800">
            <Canvas
              camera={{ position: [0, 0, 5], fov: 50 }}
              className="w-full h-full"
            >
              <ambientLight intensity={0.3} />
              <spotLight
                position={[5, 5, 5]}
                angle={0.3}
                penumbra={1}
                intensity={1}
                castShadow
              />
              <spotLight
                position={[-5, 3, 5]}
                angle={0.3}
                penumbra={1}
                intensity={0.5}
              />
              <pointLight position={[0, -5, 0]} intensity={0.3} />

              {currentWork && <MaskModel work={currentWork} />}

              <OrbitControls
                enablePan={false}
                minDistance={3}
                maxDistance={8}
                minPolarAngle={Math.PI / 4}
                maxPolarAngle={Math.PI * 3 / 4}
              />
            </Canvas>
          </div>

          <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-zinc-800/90 backdrop-blur-sm rounded-full px-6 py-3 border border-zinc-700">
            <p className="text-sm text-zinc-300">
              💡 点击脸谱不同区域进行上色，拖动旋转查看效果
            </p>
          </div>
        </main>

        <aside className="w-64 bg-zinc-800/50 border-l border-zinc-700 p-4">
          <h3 className="text-sm font-semibold text-zinc-400 mb-4">脸谱区域</h3>
          <div className="space-y-2">
            {[
              { id: 'forehead', name: '额头', color: currentWork?.regions.forehead.color },
              { id: 'leftCheek', name: '左脸颊', color: currentWork?.regions.leftCheek.color },
              { id: 'rightCheek', name: '右脸颊', color: currentWork?.regions.rightCheek.color },
              { id: 'leftEye', name: '左眼窝', color: currentWork?.regions.leftEye.color },
              { id: 'rightEye', name: '右眼窝', color: currentWork?.regions.rightEye.color },
              { id: 'nose', name: '鼻梁', color: currentWork?.regions.nose.color },
              { id: 'mouth', name: '嘴部', color: currentWork?.regions.mouth.color },
              { id: 'chin', name: '下巴', color: currentWork?.regions.chin.color },
            ].map((region) => (
              <button
                key={region.id}
                onClick={() => setSelectedRegion(region.id)}
                className="w-full flex items-center gap-3 p-3 bg-zinc-700/30 hover:bg-zinc-700/50 rounded-lg transition-colors text-left"
              >
                <div
                  className="w-6 h-6 rounded-full border-2 border-zinc-600"
                  style={{ backgroundColor: region.color || '#FFFFFF' }}
                />
                <span className="text-sm text-zinc-300">{region.name}</span>
              </button>
            ))}
          </div>
        </aside>
      </div>
    </div>
  );
}
