import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { MaskWork, ToolType, PatternAsset, RegionData } from '@/types';

interface HistoryEntry {
  type: 'region' | 'decoration';
  region?: string;
  data?: RegionData;
}

interface MaskStore {
  currentWork: MaskWork | null;
  works: MaskWork[];
  selectedTool: ToolType;
  selectedColor: string;
  selectedPattern: PatternAsset | null;
  selectedRegion: string | null;
  history: HistoryEntry[];
  historyIndex: number;

  // Actions
  createNewWork: (baseModel: MaskWork['baseModel']) => void;
  updateRegion: (region: string, data: RegionData) => void;
  setSelectedTool: (tool: ToolType) => void;
  setSelectedColor: (color: string) => void;
  setSelectedPattern: (pattern: PatternAsset | null) => void;
  setSelectedRegion: (region: string | null) => void;
  saveWork: () => void;
  loadWork: (id: string) => void;
  deleteWork: (id: string) => void;
  undo: () => void;
  redo: () => void;
  clearCurrentWork: () => void;
}

const generateId = () => Math.random().toString(36).substring(2, 15);

const createEmptyRegions = () => ({
  forehead: { color: '#FFFFFF', pattern: null },
  leftCheek: { color: '#FFFFFF', pattern: null },
  rightCheek: { color: '#FFFFFF', pattern: null },
  leftEye: { color: '#000000', pattern: null },
  rightEye: { color: '#000000', pattern: null },
  nose: { color: '#FFFFFF', pattern: null },
  mouth: { color: '#CC0000', pattern: null },
  chin: { color: '#FFFFFF', pattern: null },
});

export const useMaskStore = create<MaskStore>()(
  persist(
    (set, get) => ({
      currentWork: null,
      works: [],
      selectedTool: 'fill',
      selectedColor: '#C8102E',
      selectedPattern: null,
      selectedRegion: null,
      history: [],
      historyIndex: -1,

      createNewWork: (baseModel) => {
        const newWork: MaskWork = {
          id: generateId(),
          name: `我的脸谱作品 ${get().works.length + 1}`,
          createdAt: Date.now(),
          updatedAt: Date.now(),
          baseModel,
          regions: createEmptyRegions(),
          decorations: [],
          thumbnail: '',
        };
        set({ currentWork: newWork, history: [], historyIndex: -1 });
      },

      updateRegion: (region, data) => {
        const { currentWork, history, historyIndex } = get();
        if (!currentWork) return;

        const newHistory = history.slice(0, historyIndex + 1);
        newHistory.push({
          type: 'region',
          region,
          data: currentWork.regions[region as keyof typeof currentWork.regions],
        });

        set({
          currentWork: {
            ...currentWork,
            regions: {
              ...currentWork.regions,
              [region]: data,
            },
            updatedAt: Date.now(),
          },
          history: newHistory,
          historyIndex: newHistory.length - 1,
        });
      },

      setSelectedTool: (tool) => set({ selectedTool: tool }),
      setSelectedColor: (color) => set({ selectedColor: color }),
      setSelectedPattern: (pattern) => set({ selectedPattern: pattern }),
      setSelectedRegion: (region) => set({ selectedRegion: region }),

      saveWork: () => {
        const { currentWork, works } = get();
        if (!currentWork) return;

        const existingIndex = works.findIndex((w) => w.id === currentWork.id);
        if (existingIndex >= 0) {
          const newWorks = [...works];
          newWorks[existingIndex] = currentWork;
          set({ works: newWorks });
        } else {
          set({ works: [...works, currentWork] });
        }
      },

      loadWork: (id) => {
        const { works } = get();
        const work = works.find((w) => w.id === id);
        if (work) {
          set({ currentWork: work, history: [], historyIndex: -1 });
        }
      },

      deleteWork: (id) => {
        const { works, currentWork } = get();
        set({
          works: works.filter((w) => w.id !== id),
          currentWork: currentWork?.id === id ? null : currentWork,
        });
      },

      undo: () => {
        const { currentWork, history, historyIndex } = get();
        if (!currentWork || historyIndex < 0) return;

        const entry = history[historyIndex];
        if (entry.type === 'region' && entry.region && entry.data) {
          set({
            currentWork: {
              ...currentWork,
              regions: {
                ...currentWork.regions,
                [entry.region]: entry.data,
              },
            },
            historyIndex: historyIndex - 1,
          });
        }
      },

      redo: () => {
        const { history, historyIndex } = get();
        if (historyIndex >= history.length - 1) return;
        set({ historyIndex: historyIndex + 1 });
      },

      clearCurrentWork: () => set({ currentWork: null, history: [], historyIndex: -1 }),
    }),
    {
      name: 'mask-storage',
      partialize: (state) => ({
        works: state.works,
        selectedColor: state.selectedColor,
      }),
    }
  )
);
