import { useState } from 'react';
import { Link } from 'react-router-dom';
import { ArrowLeft, ShoppingCart, Check, Package, Truck, CreditCard } from 'lucide-react';
import { useMaskStore } from '@/store/useMaskStore';
import { baseModels } from '@/data';
import FacePreview from '@/components/FacePreview';
import type { PrintOrder } from '@/types';

const sizes = [
  { id: 'small', name: '小号', size: '5cm', price: 99, description: '精致摆件，适合桌面装饰' },
  { id: 'medium', name: '中号', size: '10cm', price: 199, description: '标准尺寸，适合收藏展示' },
  { id: 'large', name: '大号', size: '15cm', price: 399, description: '大气磅礴，适合空间装饰' },
];

const materials = [
  { id: 'resin', name: '树脂', description: '轻便耐用，色彩鲜艳', priceMultiplier: 1 },
  { id: 'ceramic', name: '陶瓷', description: '质感温润，传统工艺', priceMultiplier: 1.5 },
];

const colorModes = [
  { id: 'fullcolor', name: '全彩', description: '还原数字作品全部色彩' },
  { id: 'monochrome', name: '单色', description: '经典素雅，更具艺术感' },
];

export default function Order() {
  const { currentWork, works } = useMaskStore();
  const [selectedWorkId, setSelectedWorkId] = useState<string>(currentWork?.id || '');
  const [selectedSize, setSelectedSize] = useState<'small' | 'medium' | 'large'>('medium');
  const [selectedMaterial, setSelectedMaterial] = useState<'resin' | 'ceramic'>('resin');
  const [selectedColorMode, setSelectedColorMode] = useState<'fullcolor' | 'monochrome'>('fullcolor');
  const [quantity, setQuantity] = useState(1);
  const [step, setStep] = useState(1);

  const [shippingInfo, setShippingInfo] = useState({
    name: '',
    phone: '',
    address: '',
    city: '',
    postalCode: '',
  });

  const selectedWork = works.find((w) => w.id === selectedWorkId) || currentWork;

  const sizeInfo = sizes.find((s) => s.id === selectedSize);
  const materialInfo = materials.find((m) => m.id === selectedMaterial);

  const basePrice = sizeInfo?.price || 199;
  const materialMultiplier = materialInfo?.priceMultiplier || 1;
  const totalPrice = Math.round(basePrice * materialMultiplier * quantity);

  const handleShippingChange = (field: string, value: string) => {
    setShippingInfo({ ...shippingInfo, [field]: value });
  };

  const handleSubmitOrder = () => {
    if (!selectedWork) {
      alert('请先选择要定制的作品');
      return;
    }

    const order: PrintOrder = {
      workId: selectedWork.id,
      size: selectedSize,
      material: selectedMaterial,
      colorMode: selectedColorMode,
      quantity,
      shippingAddress: shippingInfo,
    };

    console.log('订单信息:', order);
    alert('订单提交成功！我们将尽快为您处理。');
    setStep(3);
  };

  if (works.length === 0 && !currentWork) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-zinc-900 via-zinc-800 to-zinc-900 flex items-center justify-center p-4">
        <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-12 border border-zinc-700/50 text-center max-w-md">
          <div className="text-6xl mb-4">🎭</div>
          <h2 className="text-2xl font-bold text-white mb-2">还没有可定制的作品</h2>
          <p className="text-zinc-400 mb-6">请先创作一个脸谱作品，然后再来定制实体产品</p>
          <Link
            to="/create"
            className="inline-flex items-center gap-2 px-6 py-3 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-xl transition-colors"
          >
            开始创作
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-zinc-900 via-zinc-800 to-zinc-900">
      {/* Header */}
      <header className="bg-zinc-800/80 backdrop-blur-sm border-b border-zinc-700 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center gap-4">
            <Link
              to="/"
              className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-lg transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </Link>
            <div>
              <h1 className="text-xl font-bold text-white">定制服务</h1>
              <p className="text-sm text-zinc-400">将数字作品转化为实体艺术品</p>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* 步骤指示器 */}
        <div className="flex items-center justify-center mb-8">
          {[1, 2, 3].map((s) => (
            <div key={s} className="flex items-center">
              <div
                className={`w-10 h-10 rounded-full flex items-center justify-center font-semibold ${
                  step >= s
                    ? 'bg-yellow-500 text-zinc-900'
                    : 'bg-zinc-700 text-zinc-400'
                }`}
              >
                {step > s ? <Check className="w-5 h-5" /> : s}
              </div>
              {s < 3 && (
                <div
                  className={`w-20 h-1 mx-2 ${
                    step > s ? 'bg-yellow-500' : 'bg-zinc-700'
                  }`}
                />
              )}
            </div>
          ))}
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* 左侧配置区 */}
          <div className="lg:col-span-2 space-y-6">
            {step === 1 && (
              <>
                {/* 选择作品 */}
                <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50">
                  <h3 className="text-lg font-semibold text-white mb-4">选择作品</h3>
                  <div className="grid sm:grid-cols-2 gap-4">
                    {works.map((work) => {
                      const modelInfo = baseModels.find((m) => m.id === work.baseModel);
                      return (
                        <button
                          key={work.id}
                          onClick={() => setSelectedWorkId(work.id)}
                          className={`flex items-center gap-4 p-4 rounded-xl transition-all ${
                            selectedWorkId === work.id
                              ? 'bg-yellow-500/20 border-2 border-yellow-500'
                              : 'bg-zinc-700/30 border-2 border-zinc-600 hover:border-zinc-500'
                          }`}
                        >
                          <FacePreview work={work} size={80} />
                          <div className="text-left">
                            <div className="font-semibold text-white">{work.name}</div>
                            <div className="text-xs text-zinc-400">{modelInfo?.name}</div>
                          </div>
                        </button>
                      );
                    })}
                  </div>
                </div>

                {/* 选择尺寸 */}
                <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50">
                  <h3 className="text-lg font-semibold text-white mb-4">选择尺寸</h3>
                  <div className="grid sm:grid-cols-3 gap-4">
                    {sizes.map((size) => (
                      <button
                        key={size.id}
                        onClick={() => setSelectedSize(size.id as typeof selectedSize)}
                        className={`p-4 rounded-xl transition-all text-left ${
                          selectedSize === size.id
                            ? 'bg-yellow-500/20 border-2 border-yellow-500'
                            : 'bg-zinc-700/30 border-2 border-zinc-600 hover:border-zinc-500'
                        }`}
                      >
                        <div className="text-2xl font-bold text-white mb-1">{size.size}</div>
                        <div className="text-sm text-zinc-300 mb-2">{size.name}</div>
                        <div className="text-xs text-zinc-400 mb-2">{size.description}</div>
                        <div className="text-lg font-semibold text-yellow-500">¥{size.price}</div>
                      </button>
                    ))}
                  </div>
                </div>

                {/* 选择材质 */}
                <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50">
                  <h3 className="text-lg font-semibold text-white mb-4">选择材质</h3>
                  <div className="grid sm:grid-cols-2 gap-4">
                    {materials.map((material) => (
                      <button
                        key={material.id}
                        onClick={() => setSelectedMaterial(material.id as typeof selectedMaterial)}
                        className={`p-4 rounded-xl transition-all text-left ${
                          selectedMaterial === material.id
                            ? 'bg-yellow-500/20 border-2 border-yellow-500'
                            : 'bg-zinc-700/30 border-2 border-zinc-600 hover:border-zinc-500'
                        }`}
                      >
                        <div className="font-semibold text-white mb-1">{material.name}</div>
                        <div className="text-sm text-zinc-400 mb-2">{material.description}</div>
                        <div className="text-xs text-zinc-400">
                          {material.priceMultiplier > 1 ? `+${Math.round((material.priceMultiplier - 1) * 100)}%` : '基础价格'}
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                {/* 选择颜色模式 */}
                <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50">
                  <h3 className="text-lg font-semibold text-white mb-4">颜色模式</h3>
                  <div className="grid sm:grid-cols-2 gap-4">
                    {colorModes.map((mode) => (
                      <button
                        key={mode.id}
                        onClick={() => setSelectedColorMode(mode.id as typeof selectedColorMode)}
                        className={`p-4 rounded-xl transition-all text-left ${
                          selectedColorMode === mode.id
                            ? 'bg-yellow-500/20 border-2 border-yellow-500'
                            : 'bg-zinc-700/30 border-2 border-zinc-600 hover:border-zinc-500'
                        }`}
                      >
                        <div className="font-semibold text-white mb-1">{mode.name}</div>
                        <div className="text-sm text-zinc-400">{mode.description}</div>
                      </button>
                    ))}
                  </div>
                </div>

                {/* 数量 */}
                <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50">
                  <h3 className="text-lg font-semibold text-white mb-4">购买数量</h3>
                  <div className="flex items-center gap-4">
                    <button
                      onClick={() => setQuantity(Math.max(1, quantity - 1))}
                      className="w-10 h-10 bg-zinc-700 hover:bg-zinc-600 rounded-lg text-white text-xl transition-colors"
                    >
                      -
                    </button>
                    <span className="text-2xl font-bold text-white w-12 text-center">{quantity}</span>
                    <button
                      onClick={() => setQuantity(quantity + 1)}
                      className="w-10 h-10 bg-zinc-700 hover:bg-zinc-600 rounded-lg text-white text-xl transition-colors"
                    >
                      +
                    </button>
                  </div>
                </div>
              </>
            )}

            {step === 2 && (
              <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50">
                <h3 className="text-lg font-semibold text-white mb-6">收货信息</h3>
                <div className="space-y-4">
                  <div className="grid sm:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm text-zinc-400 mb-2">姓名</label>
                      <input
                        type="text"
                        value={shippingInfo.name}
                        onChange={(e) => handleShippingChange('name', e.target.value)}
                        className="w-full px-4 py-3 bg-zinc-700/50 border border-zinc-600 rounded-xl text-white focus:border-yellow-500 focus:outline-none transition-colors"
                        placeholder="请输入收货人姓名"
                      />
                    </div>
                    <div>
                      <label className="block text-sm text-zinc-400 mb-2">电话</label>
                      <input
                        type="tel"
                        value={shippingInfo.phone}
                        onChange={(e) => handleShippingChange('phone', e.target.value)}
                        className="w-full px-4 py-3 bg-zinc-700/50 border border-zinc-600 rounded-xl text-white focus:border-yellow-500 focus:outline-none transition-colors"
                        placeholder="请输入联系电话"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm text-zinc-400 mb-2">详细地址</label>
                    <input
                      type="text"
                      value={shippingInfo.address}
                      onChange={(e) => handleShippingChange('address', e.target.value)}
                      className="w-full px-4 py-3 bg-zinc-700/50 border border-zinc-600 rounded-xl text-white focus:border-yellow-500 focus:outline-none transition-colors"
                      placeholder="请输入详细地址"
                    />
                  </div>
                  <div className="grid sm:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm text-zinc-400 mb-2">城市</label>
                      <input
                        type="text"
                        value={shippingInfo.city}
                        onChange={(e) => handleShippingChange('city', e.target.value)}
                        className="w-full px-4 py-3 bg-zinc-700/50 border border-zinc-600 rounded-xl text-white focus:border-yellow-500 focus:outline-none transition-colors"
                        placeholder="请输入城市"
                      />
                    </div>
                    <div>
                      <label className="block text-sm text-zinc-400 mb-2">邮编</label>
                      <input
                        type="text"
                        value={shippingInfo.postalCode}
                        onChange={(e) => handleShippingChange('postalCode', e.target.value)}
                        className="w-full px-4 py-3 bg-zinc-700/50 border border-zinc-600 rounded-xl text-white focus:border-yellow-500 focus:outline-none transition-colors"
                        placeholder="请输入邮编"
                      />
                    </div>
                  </div>
                </div>
              </div>
            )}

            {step === 3 && (
              <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-8 border border-zinc-700/50 text-center">
                <div className="text-6xl mb-4">🎉</div>
                <h2 className="text-2xl font-bold text-white mb-2">订单提交成功！</h2>
                <p className="text-zinc-400 mb-6">我们将尽快为您制作并发货，预计3-5个工作日送达</p>
                <div className="flex gap-4 justify-center">
                  <Link
                    to="/gallery"
                    className="px-6 py-3 bg-zinc-700 hover:bg-zinc-600 text-white rounded-xl transition-colors"
                  >
                    查看我的作品
                  </Link>
                  <Link
                    to="/create"
                    className="px-6 py-3 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-xl transition-colors"
                  >
                    继续创作
                  </Link>
                </div>
              </div>
            )}
          </div>

          {/* 右侧订单摘要 */}
          {step < 3 && (
            <div className="lg:col-span-1">
              <div className="bg-zinc-800/50 backdrop-blur-sm rounded-2xl p-6 border border-zinc-700/50 sticky top-24">
                <h3 className="text-lg font-semibold text-white mb-4">订单摘要</h3>

                {selectedWork && (
                  <div className="flex items-center gap-4 mb-6 pb-6 border-b border-zinc-700">
                    <FacePreview work={selectedWork} size={80} />
                    <div>
                      <div className="font-semibold text-white">{selectedWork.name}</div>
                      <div className="text-sm text-zinc-400">
                        {baseModels.find((m) => m.id === selectedWork.baseModel)?.name}
                      </div>
                    </div>
                  </div>
                )}

                <div className="space-y-3 mb-6">
                  <div className="flex justify-between text-sm">
                    <span className="text-zinc-400">尺寸</span>
                    <span className="text-white">{sizeInfo?.name} ({sizeInfo?.size})</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-zinc-400">材质</span>
                    <span className="text-white">{materialInfo?.name}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-zinc-400">颜色模式</span>
                    <span className="text-white">
                      {colorModes.find((m) => m.id === selectedColorMode)?.name}
                    </span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-zinc-400">数量</span>
                    <span className="text-white">{quantity}</span>
                  </div>
                </div>

                <div className="border-t border-zinc-700 pt-4 mb-6">
                  <div className="flex justify-between items-center">
                    <span className="text-zinc-400">总计</span>
                    <span className="text-2xl font-bold text-yellow-500">¥{totalPrice}</span>
                  </div>
                </div>

                {step === 1 && (
                  <button
                    onClick={() => setStep(2)}
                    disabled={!selectedWorkId}
                    className="w-full py-3 bg-yellow-500 hover:bg-yellow-400 disabled:bg-zinc-600 disabled:cursor-not-allowed text-zinc-900 font-semibold rounded-xl transition-colors"
                  >
                    下一步
                  </button>
                )}

                {step === 2 && (
                  <div className="space-y-3">
                    <button
                      onClick={handleSubmitOrder}
                      className="w-full py-3 bg-yellow-500 hover:bg-yellow-400 text-zinc-900 font-semibold rounded-xl transition-colors"
                    >
                      提交订单
                    </button>
                    <button
                      onClick={() => setStep(1)}
                      className="w-full py-3 bg-zinc-700 hover:bg-zinc-600 text-white rounded-xl transition-colors"
                    >
                      返回修改
                    </button>
                  </div>
                )}

                <div className="mt-6 pt-6 border-t border-zinc-700">
                  <div className="flex items-center gap-2 text-xs text-zinc-400 mb-2">
                    <Truck className="w-4 h-4" />
                    <span>全国包邮</span>
                  </div>
                  <div className="flex items-center gap-2 text-xs text-zinc-400 mb-2">
                    <Package className="w-4 h-4" />
                    <span>精美包装</span>
                  </div>
                  <div className="flex items-center gap-2 text-xs text-zinc-400">
                    <CreditCard className="w-4 h-4" />
                    <span>支持多种支付方式</span>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
